    if 'UNIV CALIFORNIA' in assignee.upper():
        continue

    # Get CPC codes for the cited UNIV CALIFORNIA patent
    cpc_codes = uni_cal_cpc.get(cited_pub, [])
    for cpc in cpc_codes:
        assignee_citations[assignee][cpc].add(cited_pub)

