import re
from collections import defaultdict

# Load UNIV CALIFORNIA patents data
uni_cal_file = str(locals()['var_functions.query_db:18'])
with open(uni_cal_file, 'r') as f:
    uni_cal_patents = json.load(f)

print("Processing", len(uni_cal_patents), "UNIV CALIFORNIA patents")

# Extract publication numbers and CPC codes (full subclasses)
uni_cal_pub_to_cpc = defaultdict(set)
uni_cals = set()

for patent in uni_cal_patents:
    patents_info = patent['Patents_info']
    pub_match = re.search(r'pub\. number\s+([A-Z]{2}-[A-Z0-9-]+)', patents_info)
    if not pub_match:
        pub_match = re.search(r'publication\s+no\.\s+([A-Z]{2}-[A-Z0-9-]+)', patents_info)
    if not pub_match:
        pub_match = re.search(r'publication\s+number\s+([A-Z]{2}-[A-Z0-9-]+)', patents_info)

    if pub_match:
        pub_num = pub_match.group(1)
        uni_cals.add(pub_num)

        if patent['cpc']:
            try:
                cpc_list = json.loads(patent['cpc'])
                for cpc_entry in cpc_list:
                    code = cpc_entry.get('code', '')
                    # Extract subclass (e.g., C09J from C09J11/04)
                    if code and len(code) >= 4:
                        subclass = code[:4]
                        uni_cal_pub_to_cpc[pub_num].add(subclass)
            except:
                pass

print("Extracted CPC codes for", len(uni_cals), "UNIV CALIFORNIA patents")

# Load all patents to find citations
all_patents_file = str(locals()['var_functions.query_db:22'])
with open(all_patents_file, 'r') as f:
    all_patents = json.load(f)

print("Scanning", len(all_patents), "patents for citations...")

# Find citations to UNIV CALIFORNIA patents
citation_map = defaultdict(lambda: defaultdict(set))

for patent in all_patents:
    patents_info = patent['Patents_info']

    # Extract citing patent's assignee
    citing_assignee = "UNKNOWN"
    if re.search(r'holds|hold|assigned to|is|from', patents_info, re.IGNORECASE):
        patterns = [
            r'^(.+?)(?:\s+(?:holds?|is|from|belonging to|assigned to))\s+(?:the\s+)?(?:[A-Z]{2})\s+(?:patent|application)',
            r'^(.+?)\s+holds'
        ]
        for pattern in patterns:
            match = re.search(pattern, patents_info, re.IGNORECASE)
            if match:
                candidate = match.group(1).strip()
                if candidate and len(candidate) < 100:
                    citing_assignee = candidate
                    break

    # Skip UNIV CALIFORNIA itself
    if 'UNIV CALIFORNIA' in citing_assignee.upper():
        continue

    if patent['citation']:
        try:
            citations = json.loads(patent['citation'])
            for citation in citations:
                cited_pub = citation.get('publication_number', '')
                if cited_pub and cited_pub in uni_cals:
                    # Found a citation from citing_assignee to cited_pub
                    cpc_codes = uni_cal_pub_to_cpc.get(cited_pub, [])
                    for cpc in cpc_codes:
                        citation_map[citing_assignee][cpc].add(cited_pub)
        except:
            pass

print("Found citations from", len(citation_map), "different assignees")

# Collect all unique CPC subclasses we need to resolve
all_cpc_subclasses = set()
for assignee, cpc_dict in citation_map.items():
    for cpc in cpc_dict.keys():
        all_cpc_subclasses.add(cpc)

print("Need to resolve these CPC subclasses:", sorted(all_cpc_subclasses))

# Store results
results = {
    'citation_map': dict(citation_map),
    'cpc_subclasses_to_resolve': sorted(all_cpc_subclasses)
}

print("__RESULT__:")
print(json.dumps({
    'num_assignees': len(citation_map),
    'sample_assignees': dict(list(citation_map.items())[:5]),
    'cpc_to_resolve': sorted(all_cpc_subclasses)
}))"}
